import java.util.*;
public class MockEasy {
    static int[] twoSum(int[] n,int t){Map<Integer,Integer> m=new HashMap<>();for(int i=0;i<n.length;i++){int c=t-n[i];if(m.containsKey(c))return new int[]{m.get(c),i};m.put(n[i],i);}return null;}
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    static ListNode rev(ListNode h){ListNode p=null,c=h,nx;while(c!=null){nx=c.next;c.next=p;p=c;c=nx;}return p;}
    static String str(ListNode h){StringBuilder sb=new StringBuilder();while(h!=null){sb.append(h.val);if(h.next!=null)sb.append("-");h=h.next;}return sb.toString();}
    public static void main(String[] a){System.out.println(Arrays.toString(twoSum(new int[]{2,7,11,15},9)));ListNode l=new ListNode(1);l.next=new ListNode(2);l.next.next=new ListNode(3);System.out.println(str(rev(l)));System.out.println("Mock easy: 5 min each. Clarify+approach+code+test in order.");}
}

import java.util.*;
public class MockEasy2 {
    static boolean valid(String s){Deque<Character> st=new ArrayDeque<>();for(char c:s.toCharArray()){if("([{".indexOf(c)>=0)st.push(c);else{if(st.isEmpty())return false;char t=st.pop();if(c==')'&&t!='('||c==']'&&t!='['||c=='}'&&t!='{')return false;}}return st.isEmpty();}
    static int bs(int[] a,int t){int lo=0,hi=a.length-1;while(lo<=hi){int m=lo+(hi-lo)/2;if(a[m]==t)return m;if(a[m]<t)lo=m+1;else hi=m-1;}return -1;}
    public static void main(String[] a){System.out.println(valid("()[]{}"));System.out.println(valid("(]"));System.out.println(bs(new int[]{-1,0,3,5,9,12},9));System.out.println("Parens: stack O(n). BS: lo+(hi-lo)/2 O(log n).");}
}

public class MockEasy3 {
    static String[] fizzBuzz(int n){String[] res=new String[n];for(int i=1;i<=n;i++){if(i%15==0)res[i-1]="FizzBuzz";else if(i%3==0)res[i-1]="Fizz";else if(i%5==0)res[i-1]="Buzz";else res[i-1]=String.valueOf(i);}return res;}
    static long fib(int n){if(n<=1)return n;long a=0,b=1;for(int i=2;i<=n;i++){long c=a+b;a=b;b=c;}return b;}
