import java.util.*;
public class MockMed1 {
    static int maxSub(int[] n){int max=n[0],cur=n[0];for(int i=1;i<n.length;i++){cur=Math.max(n[i],cur+n[i]);max=Math.max(max,cur);}return max;}
    static int[][] merge(int[][] iv){Arrays.sort(iv,(a,b)->a[0]-b[0]);List<int[]> res=new ArrayList<>();for(int[] x:iv){if(res.isEmpty()||res.get(res.size()-1)[1]<x[0])res.add(x);else res.get(res.size()-1)[1]=Math.max(res.get(res.size()-1)[1],x[1]);}return res.toArray(new int[0][]);}
    public static void main(String[] a){System.out.println(maxSub(new int[]{-2,1,-3,4,-1,2,1,-5,4}));System.out.println(Arrays.deepToString(merge(new int[][]{{1,3},{2,6},{8,10},{15,18}})));System.out.println("Kadane O(n) O(1). Merge intervals: sort by start O(n log n).");}
}

import java.util.*;
public class MockMed2 {
    static class LRU{LinkedHashMap<Integer,Integer> m;int c;LRU(int cap){c=cap;m=new LinkedHashMap<>(16,0.75f,true){protected boolean removeEldestEntry(Map.Entry<Integer,Integer> e){return size()>c;}};}int get(int k){return m.getOrDefault(k,-1);}void put(int k,int v){m.put(k,v);}}
    static int[] product(int[] nums){int n=nums.length;int[] res=new int[n];res[0]=1;for(int i=1;i<n;i++)res[i]=res[i-1]*nums[i-1];int right=1;for(int i=n-1;i>=0;i--){res[i]*=right;right*=nums[i];}return res;}
    public static void main(String[] a){LRU l=new LRU(2);l.put(1,1);l.put(2,2);System.out.println(l.get(1));l.put(3,3);System.out.println(l.get(2));System.out.println(Arrays.toString(product(new int[]{1,2,3,4})));System.out.println("LRU: LinkedHashMap. Product: prefix+suffix O(n) O(1).");}
}

import java.util.*;
public class MockMed3 {
    static List<List<Integer>> threeSum(int[] n){Arrays.sort(n);List<List<Integer>> res=new ArrayList<>();for(int i=0;i<n.length-2;i++){if(i>0&&n[i]==n[i-1])continue;int lo=i+1,hi=n.length-1;while(lo<hi){int s=n[i]+n[lo]+n[hi];if(s==0){res.add(Arrays.asList(n[i],n[lo],n[hi]));while(lo<hi&&n[lo]==n[lo+1])lo++;while(lo<hi&&n[hi]==n[hi-1])hi--;lo++;hi--;}else if(s<0)lo++;else hi--;}}return res;}
    static boolean jump(int[] n){int max=0;for(int i=0;i<n.length;i++){if(i>max)return false;max=Math.max(max,i+n[i]);}return true;}
    public static void main(String[] a){System.out.println(threeSum(new int[]{-1,0,1,2,-1,-4}));System.out.println(jump(new int[]{2,3,1,1,4}));System.out.println(jump(new int[]{3,2,1,0,4}));System.out.println("3Sum O(n²). Jump: greedy O(n) O(1).");}
}

public class MockHard1 {
    static String longestPalindrome(String s){String res="";for(int i=0;i<s.length();i++){String odd=expand(s,i,i),even=expand(s,i,i+1);if(odd.length()>res.length())res=odd;if(even.length()>res.length())res=even;}return res;}
    static String expand(String s,int l,int r){while(l>=0&&r<s.length()&&s.charAt(l)==s.charAt(r)){l--;r++;}return s.substring(l+1,r);}
    public static void main(String[] a){System.out.println(longestPalindrome("babad"));System.out.println(longestPalindrome("cbbd"));System.out.println("Expand around center O(n²) O(1). 2n-1 centers: n single + n-1 between.");}
}

import java.util.*;
public class MockHard2 {
    static int coin(int[] c,int amt){int[] dp=new int[amt+1];Arrays.fill(dp,amt+1);dp[0]=0;for(int i=1;i<=amt;i++)for(int x:c)if(x<=i)dp[i]=Math.min(dp[i],dp[i-x]+1);return dp[amt]>amt?-1:dp[amt];}
    static int rob(int[] n){if(n.length==1)return n[0];int a=n[0],b=Math.max(n[0],n[1]);for(int i=2;i<n.length;i++){int c=Math.max(b,a+n[i]);a=b;b=c;}return b;}
    public static void main(String[] a){System.out.println(coin(new int[]{1,5,11},15));System.out.println(coin(new int[]{2},3));System.out.println(rob(new int[]{2,7,9,3,1}));System.out.println("Coin: O(n*m) DP. Rob: O(n) O(1) rolling vars.");}
}

public class MockHard3 {
    static boolean wsearch(char[][] b,String w){for(int r=0;r<b.length;r++)for(int c=0;c<b[0].length;c++)if(dfs(b,w,r,c,0))return true;return false;}
    static boolean dfs(char[][] b,String w,int r,int c,int i){if(i==w.length())return true;if(r<0||r>=b.length||c<0||c>=b[0].length||b[r][c]!=w.charAt(i))return false;char t=b[r][c];b[r][c]='#';boolean ok=dfs(b,w,r+1,c,i+1)||dfs(b,w,r-1,c,i+1)||dfs(b,w,r,c+1,i+1)||dfs(b,w,r,c-1,i+1);b[r][c]=t;return ok;}
    static int lis(int[] n){int[] dp=new int[n.length];java.util.Arrays.fill(dp,1);int max=1;for(int i=1;i<n.length;i++){for(int j=0;j<i;j++)if(n[j]<n[i])dp[i]=Math.max(dp[i],dp[j]+1);max=Math.max(max,dp[i]);}return max;}
    public static void main(String[] a){char[][] b={{'A','B','C','E'},{'S','F','C','S'},{'A','D','E','E'}};System.out.println(wsearch(b,"ABCCED"));System.out.println(lis(new int[]{10,9,2,5,3,7,101,18}));System.out.println("WordSearch O(m*n*4^L). LIS O(n²) DP.");}
}

import java.util.*;
public class FullMock {
    // Problem: Given intervals, find minimum rooms needed (Meeting Rooms II)
    static int minRooms(int[][] ivs){Arrays.sort(ivs,(a,b)->a[0]-b[0]);PriorityQueue<Integer> ends=new PriorityQueue<>();for(int[] iv:ivs){if(!ends.isEmpty()&&ends.peek()<=iv[0])ends.poll();ends.offer(iv[1]);}return ends.size();}
    // Problem 2: Number of islands
    static int islands(char[][] g){int r=g.length,c=g[0].length,cnt=0;int[][] d={{0,1},{0,-1},{1,0},{-1,0}};for(int i=0;i<r;i++)for(int j=0;j<c;j++){if(g[i][j]=='1'){cnt++;Queue<int[]> q=new ArrayDeque<>();q.offer(new int[]{i,j});g[i][j]='0';while(!q.isEmpty()){int[] p=q.poll();for(int[] dd:d){int ni=p[0]+dd[0],nj=p[1]+dd[1];if(ni>=0&&ni<r&&nj>=0&&nj<c&&g[ni][nj]=='1'){g[ni][nj]='0';q.offer(new int[]{ni,nj});}}}}}return cnt;}
    public static void main(String[] a){System.out.println(minRooms(new int[][]{{0,30},{5,10},{15,20}}));System.out.println(islands(new char[][]{{'1','1','0'},{'0','1','0'},{'0','0','1'}}));System.out.println("Mock: 45 min = 2 min clarify+3 plan+20 code+5 test+10 discuss+5 questions.");System.out.println("Both pass: "+(minRooms(new int[][]{{0,30},{5,10},{15,20}})==2&&islands(new char[][]{{'1','1','0'},{'0','1','0'},{'0','0','1'}})==2));}
}

import java.util.*;
public class SpeedRound {
    static int[] twoSum(int[] n,int t){Map<Integer,Integer> m=new HashMap<>();for(int i=0;i<n.length;i++){int c=t-n[i];if(m.containsKey(c))return new int[]{m.get(c),i};m.put(n[i],i);}return null;}
    static boolean hasDup(int[] n){Set<Integer> s=new HashSet<>();for(int x:n)if(!s.add(x))return true;return false;}
    static int max(int[] n){int m=n[0];for(int x:n)m=Math.max(m,x);return m;}
    static int missing(int[] n){int s=n.length*(n.length+1)/2;for(int x:n)s-=x;return s;}
    static boolean isPalin(String s){int l=0,r=s.length()-1;while(l<r)if(s.charAt(l++)!=s.charAt(r--))return false;return true;}
    public static void main(String[] a){System.out.println(Arrays.toString(twoSum(new int[]{2,7,11,15},9)));System.out.println(hasDup(new int[]{1,2,3,1}));System.out.println(max(new int[]{3,1,4,1,5,9}));System.out.println(missing(new int[]{3,0,1}));System.out.println(isPalin("racecar"));boolean ok=Arrays.equals(twoSum(new int[]{2,7,11,15},9),new int[]{0,1})&&hasDup(new int[]{1,2,3,1})&&missing(new int[]{3,0,1})==2;System.out.println("All pass: "+ok);}
}

import java.util.*;
public class TimedSynth {
    // 45-minute mock: one problem per type
    static int kthLargest(int[] n,int k){PriorityQueue<Integer> pq=new PriorityQueue<>();for(int x:n){pq.offer(x);if(pq.size()>k)pq.poll();}return pq.peek();}
    static boolean canFinish(int numC,int[][] pre){int[] ind=new int[numC];List<List<Integer>> adj=new ArrayList<>();for(int i=0;i<numC;i++)adj.add(new ArrayList<>());for(int[] p:pre){adj.get(p[1]).add(p[0]);ind[p[0]]++;}Queue<Integer> q=new ArrayDeque<>();for(int i=0;i<numC;i++)if(ind[i]==0)q.offer(i);int done=0;while(!q.isEmpty()){done++;int c=q.poll();for(int nb:adj.get(c))if(--ind[nb]==0)q.offer(nb);}return done==numC;}
    static int maxSubarray(int[] n){int max=n[0],cur=n[0];for(int i=1;i<n.length;i++){cur=Math.max(n[i],cur+n[i]);max=Math.max(max,cur);}return max;}
    public static void main(String[] a){System.out.println("kthL="+kthLargest(new int[]{3,2,1,5,6,4},2));System.out.println("canFinish="+canFinish(2,new int[][]{{1,0}}));System.out.println("maxSub="+maxSubarray(new int[]{-2,1,-3,4,-1,2,1,-5,4}));boolean ok=kthLargest(new int[]{3,2,1,5,6,4},2)==5&&canFinish(2,new int[][]{{1,0}})&&maxSubarray(new int[]{-2,1,-3,4,-1,2,1,-5,4})==6;System.out.println("All pass: "+ok);}
}

