    static int meetRooms(int[][] iv){Arrays.sort(iv,(a,b)->a[0]-b[0]);PriorityQueue<Integer> pq=new PriorityQueue<>();for(int[] x:iv){if(!pq.isEmpty()&&pq.peek()<=x[0])pq.poll();pq.offer(x[1]);}return pq.size();}
    static int coinChange(int[] c,int amt){int[] dp=new int[amt+1];Arrays.fill(dp,amt+1);dp[0]=0;for(int i=1;i<=amt;i++)for(int x:c)if(x<=i)dp[i]=Math.min(dp[i],dp[i-x]+1);return dp[amt]>amt?-1:dp[amt];}
